// BLStudio — Publicar carrusel (2-10 imágenes) en Instagram
// 1) crea un container hijo por imagen, 2) crea el container padre CAROUSEL, 3) publica.
const data = $input.first().json;
const igUserId = data.ig_user_id;
const caption = data.caption || '';
let images = data.image_urls || [];
if (typeof images === 'string') { images = JSON.parse(images); }
const token = data.access_token;
const base = 'https://graph.instagram.com/v21.0';

if (!Array.isArray(images) || images.length < 2 || images.length > 10) {
  throw new Error('Un carrusel necesita entre 2 y 10 imágenes en image_urls');
}

// 1) containers hijos
const childIds = [];
for (const url of images) {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: base + '/' + igUserId + '/media',
    qs: { image_url: url, is_carousel_item: true, access_token: token },
    json: true,
  });
  childIds.push(res.id);
}

// 2) container padre
const parent = await this.helpers.httpRequest({
  method: 'POST',
  url: base + '/' + igUserId + '/media',
  qs: { media_type: 'CAROUSEL', children: childIds.join(','), caption: caption, access_token: token },
  json: true,
});

// 3) publicar
const pub = await this.helpers.httpRequest({
  method: 'POST',
  url: base + '/' + igUserId + '/media_publish',
  qs: { creation_id: parent.id, access_token: token },
  json: true,
});

return [{ json: {
  post_id: data.post_id,
  ig_media_id: pub.id,
  children: childIds,
  status: 'published',
  published_at: new Date().toISOString(),
} }];
